class Solution {
public:
    int wordCount(vector<string>& startWords, vector<string>& targetWords) {
        unordered_set<int> startWordMasks;
        for (const auto& word : startWords) {
            int mask = 0;
            for (char c : word) {
                mask |= 1 << (c - 'a');
            }
            startWordMasks.insert(mask);
        }

        int count = 0;
        for (const auto& word : targetWords) {
            int mask = 0;
            for (char c : word) {
                mask |= 1 << (c - 'a');
            }
            for (char c : word) {
                int prevMask = mask ^ (1 << (c - 'a'));
                if (startWordMasks.count(prevMask)) {
                    count++;
                    break;
                }
            }
        }
        return count;
    }
};
